   261→/**
   262→ * Filter use cases by coverage gaps
   263→ */
   264→async function filterByCoverageGaps(useCases: UseCase[]): Promise<UseCase[]> {
   265→  const report = await loadCoverageReport();
   266→  if (!report) {
   267→    console.warn('Warning: No coverage report found. Run coverage tracking first.');
   268→    return useCases;
   269→  }
   270→
