   273→    console.log('All tools covered! Nothing to run.');
   274→    return [];
   275→  }
   276→
   277→  // Filter to use cases that target uncovered tools
   278→  return useCases.filter((uc) => uc.expectedTools.some((tool) => uncoveredTools.has(tool)));
   279→}
