   317→    // Apply domain filter
   318→    if (options.domain) {
   319→      useCases = useCases.filter((uc) => uc.domain === options.domain);
   320→    }
   321→
   322→    // Apply coverage gaps filter
   323→    if (options.coverageGaps) {
   324→      useCases = await filterByCoverageGaps(useCases);
   325→    }
   326→  }
   327→
   328→  if (useCases.length === 0) {
   329→    console.log('No use cases to run.');
   330→    process.exit(0);
   331→  }
   332→
   333→  // Dry run - just list use cases
   334→  if (options.dryRun) {
   335→    console.log(`Would run ${useCases.length} use cases:\n`);
   336→    for (const uc of useCases) {
   337→      console.log(`  ${uc.id}`);
   338→      console.log(`    Domain: ${uc.domain}`);
   339→      console.log(`    Expected tools: ${uc.expectedTools.join(', ')}`);
   340→      console.log(`    Timeout: ${uc.timeout}min`);
   341→      console.log('');
   342→    }
   343→    process.exit(0);
   344→  }
   345→
   346→  // Initialize executor with MCP config for Mittwald tools
   347→  const executor = new UseCaseExecutor({
   348→    mcpConfig: DEFAULT_MCP_CONFIG,
   349→  });
   350→
   351→  // Track results
   352→  const results: ExecutionResult[] = [];
   353→  const summary: RunSummary = {
   354→    startTime: new Date(),
   355→    endTime: new Date(),
   356→    total: useCases.length,
   357→    passed: 0,
   358→    failed: 0,
   359→    timeout: 0,
   360→    cleanupFailed: 0,
   361→    results: [],
   362→  };
   363→
   364→  // Track coverage
   365→  const coverageTracker = new CoverageTracker();
   366→  await coverageTracker.loadInventory();
   367→  const beforeState = coverageTracker.getState();
   368→
   369→  console.log(`Running ${useCases.length} use cases...\n`);
   370→
   371→  // Execute each use case
   372→  for (let i = 0; i < useCases.length; i++) {
   373→    const useCase = useCases[i];
   374→    const index = i + 1;
   375→
   376→    printProgress(index, useCases.length, useCase, 'start');
   377→
   378→    // Listen to phase events
   379→    const phaseHandler = (event: PhaseEvent) => {
   380→      if (event.phase !== 'init' && event.phase !== 'complete') {
   381→        printProgress(index, useCases.length, useCase, event.phase);
   382→      }
   383→    };
   384→
   385→    executor.on('phase', phaseHandler);
   386→
   387→    try {
   388→      const execution = await executor.execute(useCase);
   389→
   390→      // Update coverage tracker
   391→      if (execution.sessionLogPath) {
   392→        await coverageTracker.parseSessionLog(execution.sessionLogPath, useCase.id);
   393→      }
   394→
   395→      // Determine result status
   396→      let status: 'passed' | 'failed' | 'timeout' | 'cleanup-failed';
   397→      if (execution.status === 'success') {
   398→        status = 'passed';
   399→        summary.passed++;
   400→      } else if (execution.status === 'timeout') {
   401→        status = 'timeout';
   402→        summary.timeout++;
   403→      } else if (execution.status === 'cleanup-failed') {
   404→        status = 'cleanup-failed';
   405→        summary.cleanupFailed++;
   406→      } else {
   407→        status = 'failed';
   408→        summary.failed++;
   409→      }
   410→
   411→      const duration = execution.endTime
   412→        ? execution.endTime.getTime() - execution.startTime.getTime()
   413→        : undefined;
   414→
   415→      printProgress(index, useCases.length, useCase, 'complete', status, duration, execution.errorMessage);
   416→
   417→      results.push({
   418→        useCaseId: useCase.id,
   419→        status,
   420→        duration,
   421→        error: execution.errorMessage,
   422→        toolsCovered: execution.toolsInvoked,
   423→      });
   424→    } catch (error) {
   425→      summary.failed++;
   426→      const errorMessage = error instanceof Error ? error.message : String(error);
   427→
   428→      printProgress(index, useCases.length, useCase, 'complete', 'failed', undefined, errorMessage);
   429→
   430→      results.push({
   431→        useCaseId: useCase.id,
   432→        status: 'failed',
   433→        error: errorMessage,
   434→        toolsCovered: [],
   435→      });
   436→    } finally {
   437→      executor.off('phase', phaseHandler);
   438→    }
   439→  }
   440→
   441→  // Finalize summary
   442→  summary.endTime = new Date();
   443→  summary.results = results;
   444→
   445→  // Calculate coverage impact
   446→  const afterReport = coverageTracker.generateReport();
   447→  summary.coverageAfter = afterReport.coveragePercent;
   448→
   449→  // Print summary
   450→  if (options.json) {
   451→    console.log(JSON.stringify(summary, null, 2));
   452→  } else {
   453→    printSummary(summary);
   454→  }
   455→
   456→  // Save summary to file
   457→  await mkdir(DEFAULT_OUTPUT_ROOT, { recursive: true });
   458→  const summaryPath = path.join(DEFAULT_OUTPUT_ROOT, '007-run-summary.json');
   459→  await writeFile(summaryPath, JSON.stringify(summary, null, 2));
   460→  console.log(`Report saved to: ${summaryPath}`);
   461→
   462→  // Exit with appropriate code
   463→  process.exit(summary.failed + summary.timeout > 0 ? 1 : 0);
   464→}
   465→
   466→// Run main
   467→main().catch((error) => {
   468→  console.error('Fatal error:', error);
   469→  process.exit(1);
   470→});
